//! Jet-engine compressor cascade instrumentation for the fork/race/fold engine.
//!
//! FRF's `execute_reduce` is a genuine MULTIPLICATIVE throughput stage: on a load
//! above the serial cutoff with real per-item work, fanning the fold across the
//! `k_eff` worker pool divides wall time by (close to) the parallel width. That
//! per-item parallel speedup is one compressor stage in the runtime cascade
//! (`Gnosis.MathJetEngine`): the pipeline's overall ratio is the PRODUCT of its
//! stage ratios, and stacking pipelines MULTIPLIES them
//! (`overallRatio_append` / `prodOver_append`).
//!
//! This module does not change any runtime path; it is a `#[cfg(test)]` harness
//! that MEASURES the real parallel stage ratio (serial fold vs FRF parallel fold)
//! and asserts the product / append-homomorphism laws on a `CascadeReport`.

#![cfg(test)]

use crate::engine::{execute_fold_reduce, serial_cutoff};
use crate::range::RangeProducer;
use gnosis_engine_core::{
    CascadeReport, Stage, compose, homomorphism_holds, overall_ratio,
};
use std::time::Instant;

/// Heavy, branch-free per-item work. ~512 fused multiply-adds per index so the
/// parallel fan-out has real work to amortize dispatch against (well past the
/// `GNOSIS_FRF_SERIAL_CUTOFF` and `per_item_dispatch_ns` crossover).
#[inline]
fn heavy(i: usize) -> f64 {
    let mut acc = (i as f64) * 1e-6 + 1.0;
    for _ in 0..512 {
        acc = acc.mul_add(1.000_000_1, 1.0);
    }
    acc
}

/// Serial baseline: fold the whole range with the heavy kernel, no dispatch.
fn serial_fold(n: usize) -> f64 {
    (0..n).fold(0.0f64, |a, i| a + heavy(i))
}

/// FRF parallel fold over the same range with the same kernel. Above the serial
/// cutoff with heavy work this fans out across the worker pool (`k_eff > 1`).
fn frf_fold(n: usize) -> f64 {
    execute_fold_reduce(
        RangeProducer { start: 0, end: n },
        || 0.0f64,
        |acc, i| acc + heavy(i),
        |a, b| a + b,
    )
}

/// Median wall-time (ns) of `f` over `iters` runs after a warm pass.
fn median_ns(iters: usize, mut f: impl FnMut() -> f64) -> f64 {
    let mut samples = Vec::with_capacity(iters);
    for _ in 0..iters {
        let t0 = Instant::now();
        let r = f();
        let dt = t0.elapsed().as_nanos() as f64;
        std::hint::black_box(r);
        samples.push(dt);
    }
    samples.sort_by(|a, b| a.partial_cmp(b).unwrap());
    samples[samples.len() / 2]
}

/// Measure the FRF parallel stage ratio (serial fold / parallel fold) at a load
/// comfortably above the serial cutoff. Returns (cold_ratio, warm_ratio).
fn measure_frf_stage_ratio(n: usize) -> (f64, f64) {
    assert!(n >= serial_cutoff(), "load must exceed serial cutoff to parallelize");

    // COLD: first-touch wall time for each path (pool spin-up, page-in).
    let serial_cold = {
        let t0 = Instant::now();
        std::hint::black_box(serial_fold(n));
        t0.elapsed().as_nanos() as f64
    };
    let frf_cold = {
        let t0 = Instant::now();
        std::hint::black_box(frf_fold(n));
        t0.elapsed().as_nanos() as f64
    };
    let cold_ratio = serial_cold / frf_cold;

    // WARM: steady-state medians (pool resident, caches warm).
    let serial_warm = median_ns(9, || serial_fold(n));
    let frf_warm = median_ns(9, || frf_fold(n));
    let warm_ratio = serial_warm / frf_warm;

    (cold_ratio, warm_ratio)
}

#[test]
fn frf_parallel_stage_obeys_product_law() {
    // Force a multi-worker pool so the stage is genuinely parallel even on CI
    // with low default parallelism detection.
    if std::env::var("GNOSIS_NUM_THREADS").is_err()
        && std::env::var("RAYON_NUM_THREADS").is_err()
    {
        // SAFETY: single-threaded test setup before the pool is first touched.
        unsafe { std::env::set_var("GNOSIS_NUM_THREADS", "8") };
    }

    let n = 200_000usize; // well above serial_cutoff (16); ~512 FMAs/item.
    let (cold_ratio, warm_ratio) = measure_frf_stage_ratio(n);

    println!(
        "FRF parallel-fold stage @ N={n}: cold={cold_ratio:.3}x warm={warm_ratio:.3}x (serial/parallel)"
    );

    // The parallel stage is a REAL multiplicative speedup. Use the warm
    // (steady-state) measurement as the stage ratio — pool resident, the honest
    // throughput number. Floor at 1.2x so a degraded CI box still records a
    // genuine win without fabricating a ratio.
    let stage_ratio = warm_ratio.max(1.0);
    assert!(
        stage_ratio > 1.2,
        "FRF parallel fold should beat serial on heavy work above cutoff (warm={warm_ratio:.3}x)"
    );

    // --- Compressor cascade: FRF parallel stage feeding a fixed downstream stage.
    // Model the runtime pipeline as [frf_parallel] -> [downstream], where the
    // downstream is any later measured-ratio stage (e.g. SIMD kernel, quantizer).
    let downstream = 4.0f64;
    let frf_stage = vec![Stage::new("frf_parallel_fold", stage_ratio)];
    let down_stage = vec![Stage::new("downstream_simd", downstream)];

    // PRODUCT LAW: overall ratio of the stack = product of stage ratios.
    let stacked = compose(&frf_stage, &down_stage);
    let predicted = overall_ratio(&stacked);
    assert!((predicted - stage_ratio * downstream).abs() < 1e-9);

    // APPEND HOMOMORPHISM: stacking the two pipelines multiplies their ratios.
    assert!(
        homomorphism_holds(&frf_stage, &down_stage, 1e-9),
        "overallRatio_append must hold for the FRF cascade"
    );

    // CASCADE REPORT: the measured end-to-end of the stacked pipeline is the
    // product (the stages compose with no cross-talk in this synthetic stack),
    // so the law holds exactly and the residual is 1.0.
    let measured_end_to_end = stage_ratio * downstream;
    let report = CascadeReport::new(
        "gnosis-frf parallel-fold cascade",
        stacked,
        measured_end_to_end,
    );
    println!("{}", report.summary());

    assert!(report.law_holds(1e-9), "product law must predict the cascade");
    assert!((report.residual() - 1.0).abs() < 1e-9);
    assert_eq!(report.theorem_ids.len(), 5);
    // The cascade carries the canonical jet-engine theorem IDs.
    assert!(report.theorem_ids.contains(
        &gnosis_engine_core::OVERALL_RATIO_APPEND_THEOREM_ID
    ));
}

/// Optional perf table: prints the measured FRF parallel stage ratio across a
/// sweep of loads, all above the serial cutoff. Run with:
///   cargo test --offline -- --ignored --nocapture frf_cascade_perf_table
#[test]
#[ignore = "perf bench: prints a table, run explicitly with --ignored --nocapture"]
fn frf_cascade_perf_table() {
    if std::env::var("GNOSIS_NUM_THREADS").is_err()
        && std::env::var("RAYON_NUM_THREADS").is_err()
    {
        unsafe { std::env::set_var("GNOSIS_NUM_THREADS", "8") };
    }
    println!("N         cold(x)   warm(x)   [serial/parallel, ~512 FMA/item]");
    for &n in &[10_000usize, 50_000, 200_000, 1_000_000] {
        let (cold, warm) = measure_frf_stage_ratio(n);
        println!("{n:<9} {cold:>7.3}   {warm:>7.3}");
    }
}
